CustomField.formula:
IF(
    ISPICKVAL(Factor_PriceExponential__c,"TC以上"),1.0,
    IF(
        ISPICKVAL(Factor_PriceExponential__c, "WC以上TC未満"),
        IF(
            ISBLANK(TEXT(Factor_PriceExponential_Manual2__c)),0.8,VALUE(TEXT(Factor_PriceExponential_Manual2__c))
        ),
        IF(
            ISPICKVAL(Factor_PriceExponential__c, "WC未満"),
            IF(
                ISBLANK(TEXT(Factor_PriceExponential_Manual__c )),0.6,VALUE(TEXT(Factor_PriceExponential_Manual__c ))
            ),0
        )
    )
)
